import org.opensaml.saml.saml2.core.SAMLResponse;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.boot.autoconfigure.security.servlet.SecurityAutoConfiguration;
import org.springframework.context.annotation.Bean;
import org.springframework.security.core.userdetails.User;
import org.springframework.security.core.userdetails.UserDetailsService;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.security.saml.SAMLAuthenticationProvider;
import org.springframework.security.saml.SAMLEntryPoint;
import org.springframework.security.saml.SAMLProcessingFilter;
import org.springframework.security.saml.SAMLServiceRegistry;
import org.springframework.security.saml.SAMLUserDetailsService;
import org.springframework.security.saml.SAMLParentAuthenticationProvider;
import org.springframework.security.web.authentication.SavedRequestAwareAuthenticationSuccessHandler;
import org.springframework.web.servlet.config.annotation.EnableWebMvc;

@SpringBootApplication(exclude = SecurityAutoConfiguration.class)
@EnableWebMvc
public class SamlApplication {

    @Bean
    public SAMLProcessingFilter samlProcessingFilter() {
        SAMLProcessingFilter filter = new SAMLProcessingFilter();
        filter.setAuthenticationSuccessHandler(authenticationSuccessHandler());
        return filter;
    }

    @Bean
    public SAMLAuthenticationProvider samlAuthenticationProvider() {
        SAMLAuthenticationProvider provider = new SAMLAuthenticationProvider();
        provider.setSamlUserDetailsService(userDetailsService());
        return provider;
    }

    @Bean
    public SAMLUserDetailsService userDetailsService() {
        return new SAMLUserDetailsService() {
            @Override
            public User loadUserBySAMLAssertion(SAMLResponse samlResponse) {
                // Extract user attributes from assertion
                String username = samlResponse.getNameID().getValue();
                String email = samlResponse.getAttributeStatement().getAttribute(0).getAttributeValue();

                // Create authenticated session
                User user = new User(username, new BCryptPasswordEncoder().encode("password"), "USER");
                user.getAttributes().put("email", email);
                return user;
            }
        };
    }

    @Bean
    public SAMLEntryPoint samlEntryPoint() {
        SAMLEntryPoint entryPoint = new SAMLEntryPoint();
        entryPoint.setSamlServiceRegistry(samlServiceRegistry());
        return entryPoint;
    }

    @Bean
    public SAMLServiceRegistry samlServiceRegistry() {
        SAMLServiceRegistry registry = new SAMLServiceRegistry();
        registry.registerService("sp", samlAuthenticationProvider());
        return registry;
    }

    @Bean
    public SavedRequestAwareAuthenticationSuccessHandler authenticationSuccessHandler() {
        SavedRequestAwareAuthenticationSuccessHandler handler = new SavedRequestAwareAuthenticationSuccessHandler();
        handler.setTargetUrlParameter("targetUrl");
        return handler;
    }
}